// Solution
function projectQuery(query, allowedFields) {
  var projectedQuery = {};
  for (var field of allowedFields) {
    if (field in query) {
      projectedQuery[field] = query[field];
    } else if (typeof query[field] === 'object') {
      projectedQuery[field] = query[field];
    }
  }
  return projectedQuery;
}

solutions.python:
class Solution:
  def projectQuery(self, query, allowedFields):
    projectedQuery = {}
    for field in allowedFields:
      if field in query:
        projectedQuery[field] = query[field]
      elif isinstance(query[field], dict):
        projectedQuery[field] = query[field]
    return projectedQuery
